css_snippet:
a {
  text-decoration: underline; /* Ensure underline is present */
  text-underline-offset: 0.2em; /* Adjust to move underline away from text */
  text-decoration-thickness: 1px; /* Control the thickness of the underline */
  text-decoration-color: var(--primary-color, #007bff); /* Customize color */
}

a:hover {
  text-decoration-color: var(--hover-color, #0056b3);
  text-decoration-thickness: 2px; /* A subtle hover effect */
}
